#include <vector>
#include <unordered_map>
using namespace std;

class Solution {
public:
    bool checkSubarraySum(const vector<int>& nums, int k) {
        unordered_map<int, int> remainderMap;
        remainderMap[0] = -1; // Handle case where subarray starts from index 0
        int cumulativeSum = 0;

        for (int i = 0; i < nums.size(); ++i) {
            cumulativeSum += nums[i];
            if (k != 0) {
                cumulativeSum %= k;
            }

            if (remainderMap.find(cumulativeSum) != remainderMap.end()) {
                if (i - remainderMap[cumulativeSum] > 1) {
                    return true;
                }
            } else {
                remainderMap[cumulativeSum] = i;
            }
        }
        return false;
    }
};

